/**
 * User notification preferences model.
 *
 * Supports per-channel notification preferences for email, SMS, and webhook.
 *
 * History: Originally designed for email-only (Agent 3). Refactored to
 * multi-channel after SMS support was added (Agent 8) and webhook already
 * existed. The email-only assumption is no longer valid — each channel
 * now has its own independent preferences.
 */

import type { NotificationType } from './notification.js';

/**
 * Base preferences shared by all notification channels.
 * Each channel has an enabled switch and subscribed categories.
 */
export interface ChannelPreferences {
  /** Master switch for this channel */
  enabled: boolean;
  /** Notification types the user wants to receive on this channel */
  subscribedCategories: NotificationType[];
}

/**
 * How often email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily-digest': batched into a daily summary
 * - 'weekly-digest': batched into a weekly summary
 * - 'none': email notifications disabled via frequency
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Email-specific notification preferences.
 * Extends base with frequency control (digest support).
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency */
  frequency: EmailFrequency;
}

/**
 * SMS notification preferences.
 * SMS is always immediate delivery — no frequency/digest support.
 */
export interface SMSPreferences extends ChannelPreferences {}

/**
 * Webhook notification preferences.
 * Webhooks are always immediate delivery — no frequency/digest support.
 */
export interface WebhookPreferences extends ChannelPreferences {}

/**
 * Full user notification preferences record.
 * Each channel has its own independent preferences section.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SMSPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only
 * provided fields are updated.
 */
export interface UpdateEmailPreferences {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSMSPreferences {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferences {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Union type for updating any channel's preferences.
 */
export type UpdateChannelPreferences =
  | UpdateEmailPreferences
  | UpdateSMSPreferences
  | UpdateWebhookPreferences;

/**
 * All notification types that are subscribable by default.
 */
export const DEFAULT_SUBSCRIBED_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'user-welcome',
  'user-updated',
  'system-alert',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...DEFAULT_SUBSCRIBED_CATEGORIES],
};

/**
 * Default SMS preferences for new users.
 * SMS is disabled by default — users must opt in.
 */
export const DEFAULT_SMS_PREFERENCES: SMSPreferences = {
  enabled: false,
  subscribedCategories: [...DEFAULT_SUBSCRIBED_CATEGORIES],
};

/**
 * Default webhook preferences for new users.
 * Webhooks are disabled by default — users must opt in.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  subscribedCategories: [...DEFAULT_SUBSCRIBED_CATEGORIES],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Stores channel preferences (email, sms, webhook) as JSON strings in the database.
 *
 * Backward compatible: records missing sms/webhook fields get defaults on read.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences, SMSPreferences, WebhookPreferences } from '../models/user-preferences.js';
import { DEFAULT_SMS_PREFERENCES, DEFAULT_WEBHOOK_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    // Backward compatibility: old records may lack sms/webhook fields
    const sms = record['sms']
      ? (JSON.parse(record['sms'] as string) as SMSPreferences)
      : { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] };

    const webhook = record['webhook']
      ? (JSON.parse(record['webhook'] as string) as WebhookPreferences)
      : { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] };

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailPreferences,
      sms,
      webhook,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 * Each channel has independent enabled/subscribedCategories settings.
 * Email additionally supports frequency (digest) settings.
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferences,
  UpdateSMSPreferences,
  UpdateWebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const now = new Date();
    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };

    return this.preferencesRepository.save(prefs);
  }

  /**
   * Update email preferences for a user. Creates defaults first if
   * no preferences exist yet.
   */
  updateEmailPreferences(userId: string, updates: UpdateEmailPreferences): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedEmail = {
      ...current.email,
      ...updates,
    };

    if (updates.subscribedCategories) {
      updatedEmail.subscribedCategories = [...updates.subscribedCategories];
    }

    const updated = this.preferencesRepository.update(current.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated email preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Update SMS preferences for a user. Creates defaults first if
   * no preferences exist yet.
   */
  updateSMSPreferences(userId: string, updates: UpdateSMSPreferences): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedSMS = {
      ...current.sms,
      ...updates,
    };

    if (updates.subscribedCategories) {
      updatedSMS.subscribedCategories = [...updates.subscribedCategories];
    }

    const updated = this.preferencesRepository.update(current.id, {
      sms: updatedSMS,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated SMS preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Update webhook preferences for a user. Creates defaults first if
   * no preferences exist yet.
   */
  updateWebhookPreferences(userId: string, updates: UpdateWebhookPreferences): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedWebhook = {
      ...current.webhook,
      ...updates,
    };

    if (updates.subscribedCategories) {
      updatedWebhook.subscribedCategories = [...updates.subscribedCategories];
    }

    const updated = this.preferencesRepository.update(current.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated webhook preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   *
   * Returns true if:
   * - No preferences exist (defaults allow all notifications)
   * - The channel is enabled AND the notification type is in the user's
   *   subscribed categories for that channel
   * - For email: also checks that frequency is not 'none'
   */
  shouldSend(channel: NotificationChannel, userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences stored — default is to send all notifications
    if (!prefs) {
      return true;
    }

    switch (channel) {
      case 'email':
        return this.checkEmailPreferences(prefs, userId, notificationType);
      case 'sms':
        return this.checkChannelPreferences(prefs.sms, 'sms', userId, notificationType);
      case 'webhook':
        return this.checkChannelPreferences(prefs.webhook, 'webhook', userId, notificationType);
      default:
        // Unknown channels (e.g. in-app) — allow by default
        return true;
    }
  }

  /**
   * Check whether an email notification should be sent to a user.
   * Kept for backward compatibility — delegates to shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend('email', userId, notificationType);
  }

  /**
   * Delete preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);
    if (!prefs) {
      return false;
    }
    return this.preferencesRepository.delete(prefs.id);
  }

  private checkEmailPreferences(
    prefs: UserPreferences,
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    if (!prefs.email.enabled) {
      this.logger.debug(`Email disabled for user: ${userId}`);
      return false;
    }

    if (prefs.email.frequency === 'none') {
      this.logger.debug(`Email frequency 'none' for user: ${userId}`);
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.debug(`User ${userId} not subscribed to ${notificationType} on email`);
      return false;
    }

    return true;
  }

  private checkChannelPreferences(
    channelPrefs: { enabled: boolean; subscribedCategories: NotificationType[] },
    channel: string,
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    if (!channelPrefs.enabled) {
      this.logger.debug(`${channel} disabled for user: ${userId}`);
      return false;
    }

    if (!channelPrefs.subscribedCategories.includes(notificationType)) {
      this.logger.debug(`User ${userId} not subscribed to ${notificationType} on ${channel}`);
      return false;
    }

    return true;
  }
}

