// Check user preferences before sending (if preferences service is configured)
// TODO: Preferences currently only support the 'email' channel. Now that SMS is
// a supported channel, the UserPreferences model needs to be extended with SMS
// preferences (enabled, frequency, subscribedCategories) and a corresponding
// shouldSendSMS() method added to PreferencesService. Until then, SMS notifications
// bypass preference checks and are always sent.
if (this.preferencesService && payload.channel === 'email') {
  const userId = (payload.metadata?.['userId'] as string) ?? payload.recipient;
  if (!this.preferencesService.shouldSendEmail(userId, payload.notificationType)) {
    this.logger.info(
      `Notification suppressed by user preferences: ${payload.notificationType} for ${payload.recipient}`,
    );
    const record = this.createRecord(payload, false, true);
    // Suppressed notifications don't emit events, so log directly
    if (this.historyService) {
      this.historyService.log(record, payload.metadata);
    }
    return record;
  }
}

